mapper.select:
SELECT
sch.id, sch.venue_id, sch.name, sch.schedule_date, sch.start_time, sch.end_time,
sch.max_count, sch.booked_count, sch.status, sch.remark,
sch.enabled, sch.create_time, sch.update_time
FROM act_schedule sch
INNER JOIN act_venue v ON sch.venue_id = v.id
WHERE sch.enabled = '1' AND v.enabled = '1'

    AND sch.venue_id = #{req.venueId}


    AND sch.name LIKE CONCAT('%', #{req.name}, '%')


    AND sch.schedule_date = #{req.scheduleDate}


    AND sch.status = #{req.status}


    ${req.dataScopeSql}

ORDER BY sch.schedule_date ASC, sch.start_time ASC, sch.id DESC

mapper.update:
UPDATE act_schedule
SET booked_count = booked_count + #{count}
WHERE id = #{scheduleId}
